SELECT [Sales Cr_Memo Line].Type, [Sales Cr_Memo Line].No_, [Sales Cr_Memo Line].Quantity, [Sales Cr_Memo Line].[Unit of Measure], [Sales Cr_Memo Line].[Constant Variable Code], [Sales Cr_Memo Line].[Assortment Code], [Sales Cr_Memo Line].[No_ of Pairs], [Salesperson_Purchaser].Name AS Salesperson, [Sales Cr_Memo Line].[Return Reason Code], [Sales Cr_Memo Line].[Customer Price Group], [Sales Cr_Memo Line].[Average Unit Price], [Sales Cr_Memo Header].[Document Date], [Sales Cr_Memo Header].[Salesperson Code], [Sales Cr_Memo Line].[Constant Variable Code] AS ColorCode, [Sales Cr_Memo Header].[Sell-to Customer No_], Val([Line Amount])-Val([Inv_ Discount Amount]) AS SalesValue
FROM [Sales Cr_Memo Line] INNER JOIN ([Sales Cr_Memo Header] LEFT JOIN Salesperson_Purchaser ON [Sales Cr_Memo Header].[Salesperson Code] = [Salesperson_Purchaser].Code) ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_
WHERE ((([Sales Cr_Memo Line].Type)=19)) OR ((([Sales Cr_Memo Line].Type)=20));

